"""stl_normal_repair.py — repairs inverted normals in ASCII STL files.

Usage:
    python stl_normal_repair.py <file.stl>

Repairs the file in place by replacing declared normals with the normal
computed from the vertex winding order (right-hand rule). Prints a JSON
object to stdout:
    {"valid": true/false, "repaired": <int>, "issues": [...]}
"""
import json
import math
import re
import sys


def _cross(a, b):
    return (
        a[1] * b[2] - a[2] * b[1],
        a[2] * b[0] - a[0] * b[2],
        a[0] * b[1] - a[1] * b[0],
    )


def _sub(a, b):
    return (a[0] - b[0], a[1] - b[1], a[2] - b[2])


def _magnitude(v):
    return math.sqrt(v[0] ** 2 + v[1] ** 2 + v[2] ** 2)


def _normalize(v):
    mag = _magnitude(v)
    if mag < 1e-12:
        return (0.0, 0.0, 0.0)
    return (v[0] / mag, v[1] / mag, v[2] / mag)


def _dot(a, b):
    return a[0] * b[0] + a[1] * b[1] + a[2] * b[2]


def _winding_normal(v1, v2, v3):
    """Return the unit normal implied by the right-hand winding rule."""
    edge1 = _sub(v2, v1)
    edge2 = _sub(v3, v1)
    raw = _cross(edge1, edge2)
    return _normalize(raw)


def _parse_vertex(line):
    parts = line.strip().split()
    if parts[0] != "vertex" or len(parts) < 4:
        return None
    return (float(parts[1]), float(parts[2]), float(parts[3]))


def _parse_normal(line):
    parts = line.strip().split()
    # parts: ['facet', 'normal', x, y, z]
    if len(parts) < 5:
        return None
    return (float(parts[2]), float(parts[3]), float(parts[4]))


def repair_stl(path: str) -> dict:
    issues = []
    repaired = 0

    with open(path, "r", errors="replace") as fh:
        lines = fh.readlines()

    output_lines = []
    i = 0

    while i < len(lines):
        line = lines[i]
        stripped = line.strip()

        if stripped.startswith("facet normal"):
            # Parse declared normal
            declared = _parse_normal(stripped)
            if declared is None:
                issues.append(f"Malformed facet normal at line {i + 1}")
                output_lines.append(line)
                i += 1
                continue

            facet_start = i
            facet_lines = [line]  # facet normal ...
            i += 1

            # Expect 'outer loop'
            if i < len(lines) and lines[i].strip() == "outer loop":
                facet_lines.append(lines[i])
                i += 1
            else:
                issues.append(f"Expected 'outer loop' at line {i + 1}")
                output_lines.extend(facet_lines)
                continue

            # Parse 3 vertices
            vertices = []
            vertex_lines = []
            for _ in range(3):
                if i < len(lines):
                    vline = lines[i]
                    v = _parse_vertex(vline)
                    if v is not None:
                        vertices.append(v)
                        vertex_lines.append(vline)
                    else:
                        issues.append(f"Malformed vertex at line {i + 1}")
                        vertex_lines.append(vline)
                    i += 1

            facet_lines.extend(vertex_lines)

            # Expect 'endloop'
            if i < len(lines) and lines[i].strip() == "endloop":
                facet_lines.append(lines[i])
                i += 1
            else:
                issues.append(f"Expected 'endloop' at line {i + 1}")

            # Expect 'endfacet'
            if i < len(lines) and lines[i].strip() == "endfacet":
                facet_lines.append(lines[i])
                i += 1
            else:
                issues.append(f"Expected 'endfacet' at line {i + 1}")

            if len(vertices) == 3:
                winding_n = _winding_normal(*vertices)
                mag = _magnitude(_cross(
                    _sub(vertices[1], vertices[0]),
                    _sub(vertices[2], vertices[0])
                ))

                if mag < 1e-12:
                    # Degenerate triangle
                    issues.append(
                        f"Degenerate triangle at line {facet_start + 1} (zero area)"
                    )
                    output_lines.extend(facet_lines)
                    continue

                dot = _dot(declared, winding_n)

                if dot < 0.0:
                    # Inverted normal — flip to match winding
                    nx, ny, nz = winding_n
                    # Preserve original indentation
                    indent_match = re.match(r'^(\s*)', facet_lines[0])
                    indent = indent_match.group(1) if indent_match else "  "
                    new_facet_line = f"{indent}facet normal {nx:.10g} {ny:.10g} {nz:.10g}\n"
                    facet_lines[0] = new_facet_line
                    repaired += 1
                elif abs(dot - 1.0) > 1e-4 and dot > 0.0:
                    # Direction consistent but not well normalised — fix silently
                    nx, ny, nz = winding_n
                    indent_match = re.match(r'^(\s*)', facet_lines[0])
                    indent = indent_match.group(1) if indent_match else "  "
                    new_facet_line = f"{indent}facet normal {nx:.10g} {ny:.10g} {nz:.10g}\n"
                    facet_lines[0] = new_facet_line
                    # Not counted as a repaired inverted normal

            output_lines.extend(facet_lines)
        else:
            output_lines.append(line)
            i += 1

    # Write repaired file back in place
    with open(path, "w") as fh:
        fh.writelines(output_lines)

    # --- Post-repair validation ---
    # Re-read and validate
    with open(path, "r", errors="replace") as fh:
        lines2 = fh.readlines()

    triangles = []
    j = 0
    while j < len(lines2):
        s = lines2[j].strip()
        if s.startswith("facet normal"):
            dec = _parse_normal(s)
            verts = []
            j += 1
            if j < len(lines2) and lines2[j].strip() == "outer loop":
                j += 1
                for _ in range(3):
                    if j < len(lines2):
                        v = _parse_vertex(lines2[j])
                        if v:
                            verts.append(v)
                        j += 1
            # skip endloop, endfacet
            while j < len(lines2) and lines2[j].strip() not in ("", "endloop", "endfacet"):
                j += 1
            j += 1  # endloop
            if j < len(lines2) and lines2[j].strip() == "endfacet":
                j += 1

            if dec and len(verts) == 3:
                triangles.append((dec, verts))
        else:
            j += 1

    if not triangles:
        issues.append("No valid faces found after repair")

    # Check for remaining inverted normals
    post_issues = list(issues)  # copy issues found during repair
    remaining_inverted = 0
    for idx, (dec, verts) in enumerate(triangles):
        wn = _winding_normal(*verts)
        mag = _magnitude(_cross(_sub(verts[1], verts[0]), _sub(verts[2], verts[0])))
        if mag < 1e-12:
            continue
        dot = _dot(dec, wn)
        if dot < 0.0:
            remaining_inverted += 1

    if remaining_inverted > 0:
        post_issues.append(
            f"{remaining_inverted} face(s) still have inverted normals after repair"
        )

    # Manifold check
    edge_count: dict = {}
    for _, verts in triangles:
        rounded = [tuple(round(x, 6) for x in v) for v in verts]
        for k in range(3):
            edge = tuple(sorted([rounded[k], rounded[(k + 1) % 3]]))
            edge_count[edge] = edge_count.get(edge, 0) + 1

    open_edges = sum(1 for cnt in edge_count.values() if cnt == 1)
    if open_edges > 0:
        post_issues.append(f"Mesh has {open_edges} open edge(s) — not a closed solid")

    valid = len(post_issues) == 0

    return {
        "valid": valid,
        "repaired": repaired,
        "issues": post_issues,
    }


if __name__ == "__main__":
    if len(sys.argv) < 2:
        print(json.dumps({"error": "usage: stl_normal_repair.py <file.stl>"}))
        sys.exit(1)
    result = repair_stl(sys.argv[1])
    print(json.dumps(result))
